var INPUT_PIN = 0;
var OUTPUT_PIN = 1;
var MAX_STORED_POWER = 1500;//2000 watts
var MULTIPLIER = 255/1023;
var LOG_BASE = 1.0749111034571373359815489867558;
var availablePowerPercent = 0;
var availablePower = MAX_STORED_POWER/2;
var receivedPower = 0;
var AVAIL_POWER_PROP = "Available power (%)";
var CHARGE_RATE = 19; // power units per second
var LOOP_DELAY = 500; // msec

function setup(){
	setImage('100');
	IoEClient.setup({
		type: "Battery",
		states: [
			{
			name: "Available power",
			type: "number",
			unit: '%',
			controllable: false
			}
	 ]
	 });
	 
	 IoEClient.onInputReceive = function(input) {
	 	processData(input, true);
	 };
	 
	 var init_percent = availablePower/MAX_STORED_POWER*100;
	 availablePowerPercent = restoreProperty(AVAIL_POWER_PROP, init_percent);
	 if(availablePowerPercent < 0 || availablePowerPercent > 100)
	 	availablePowerPercent = init_percent;
	 availablePower = availablePowerPercent*MAX_STORED_POWER/100;
	 
	 sendReport();

}

function restoreProperty(propertyName, defaultValue)
{
	var value = getDeviceProperty(getName(), propertyName);
	if ( !(value === "" || value == "undefined") ){
		if ( typeof(defaultValue) == "number" )
			value = Number(value);
		
		setDeviceProperty(getName(), propertyName, value);
		return value;
	}
	
	return defaultValue;
}

function print(text){
	Serial.println(text);
}
function loop(){
	availablePowerPercent = (availablePower/MAX_STORED_POWER) * 100;
	if (availablePowerPercent < 10)
		setImage('Battery_0');
	else if (availablePowerPercent < 30)
		setImage('Battery_20');
	else if (availablePowerPercent < 50)
		setImage('Battery_40');
	else if (availablePowerPercent < 70)
		setImage('Battery_60');
	else if (availablePowerPercent < 90)
		setImage('Battery_80');
	else if (availablePowerPercent <= 100)
        setImage('Battery_100');
	else
		if (availablePowerPercent < 0 || availablePowerPercent > 100){
			throw 'Out of range';
		}

	sendReport();
	delay(LOOP_DELAY);
	receivePower(LOOP_DELAY*3);
	sendPower();
	delay(LOOP_DELAY*2);
}

function receivePower(timeDeltaMsec){
	var receivedPowerRaw = analogRead(0);
	if(receivedPowerRaw > 0){
		receivedPower = Math.pow(LOG_BASE, analogRead(0) * MULTIPLIER);
		//Serial.println(receivedPower);
		receivedPower = Math.min(receivedPower, CHARGE_RATE * timeDeltaMsec * 0.001);
	}
	else 
		receivedPower = 0;
	availablePower += receivedPower;
	if (availablePower > MAX_STORED_POWER){
		availablePower = MAX_STORED_POWER;
	}
	//Serial.println('receivedPower: ' + receivedPower);
	//Serial.println('Available: ' + availablePower);
}

function sendPower(){
	var totalPowerUsed = 0;
	var currentWattage = 0;
	var numberOfSlots = parseInt(getSlotsCount());
	var deviceAtPort = false;
	for (var i = 1; i < numberOfSlots; i++){//Start at 1 because 0 is the input port
		currentWattage = getAttributeOfDeviceAtSlot('wattage', i);
		if (currentWattage === null || currentWattage === undefined){
			currentWattage = 0;
		}
		else{
			currentWattage = parseInt(currentWattage);
			deviceAtPort = true;
		}
		totalPowerUsed += currentWattage;
		if (deviceAtPort){
			if (availablePower > currentWattage){
				//Serial.println('Sending ' + currentWattage + ' to ' + i);
				outputElectricity(i, currentWattage);
				availablePower -= currentWattage;
			}
			else{
				outputElectricity(i, 1);
			}
		}
		deviceAtPort = false;
	}
	if (availablePower < 0){
		availablePower = 0;
	}
}


function sendReport()
{
	IoEClient.reportStates(availablePowerPercent.toFixed(2));
	setDeviceProperty(getName(), AVAIL_POWER_PROP, availablePowerPercent.toFixed(2));
}

function setImage(component){
    setComponentOpacity(component, 1);
   
    if('Battery_0' != component)
        setComponentOpacity('Battery_0', 0);
    if('Battery_20' != component)
        setComponentOpacity('Battery_20', 0);
    if('Battery_40' != component)
        setComponentOpacity('Battery_40', 0);
    if('Battery_60' != component)
        setComponentOpacity('Battery_60', 0);
    if('Battery_80' != component)
        setComponentOpacity('Battery_80', 0);
    if('Battery_100' != component)
        setComponentOpacity('Battery_100', 0);
       
    //Serial.println(component);   
   
}

function outputElectricity(port, value){
	var el_log = Math.floor(Math.log(value)/Math.log(LOG_BASE));
	if(el_log < 0)
		el_log = 0;
	else if (el_log > 255)
		el_log = 255;
//	Serial.println(el_log);
	analogWrite(port, el_log);
}

