from gpio import *
from time import *
from ioeclient import *
from environment import *
from physical import *
import math

INPUT_PIN = 0
OUTPUT_PIN = 1
MAX_STORED_POWER = 1500.0 #2000 watts
MULTIPLIER = float(255)/1023
LOG_BASE = 1.0749111034571373359815489867558
availablePowerPercent = 0.0
availablePower = float(MAX_STORED_POWER)/2.0
receivedPower = 0
AVAIL_POWER_PROP="Available power (%)"
CHARGE_RATE = 19
LOOP_DELAY = 500

def setup():
    setImage('100')
    IoEClient.setup({
        "type": "Battery",
        "states": [
            {
            "name": "Available power",
            "type": "number",
            "unit": '%',
            "controllable": False
            }
     ]
     })

    IoEClient.onInputReceive(onInputReceiveDone)

    global availablePowerPercent
    global availablePower

    init_percent = availablePower/MAX_STORED_POWER*100
    availablePowerPercent = restoreProperty(AVAIL_POWER_PROP, init_percent)
    if availablePowerPercent < 0 or availablePowerPercent > 100:
        availablePowerPercent = init_percent
    availablePower = availablePowerPercent*MAX_STORED_POWER/100

    sendReport()


def onInputReceiveDone(input):
    processData(input, True)

def restoreProperty(propertyName, defaultValue):
    value = getDeviceProperty(getName(), propertyName)
    if  not (value is "" or value is None):
        if  type(defaultValue) is float :
            value = float(value)

        setDeviceProperty(getName(), propertyName, value)
        return value
    return defaultValue


def main():
    global availablePowerPercent
    global availablePower
    global MAX_STORED_POWER
    setup()
    while True:
        availablePowerPercent = (float(availablePower)/MAX_STORED_POWER) * 100
        if availablePowerPercent < 10:
            setImage('Battery_0')
        elif availablePowerPercent < 30:
            setImage('Battery_20')
        elif availablePowerPercent < 50:
            setImage('Battery_40')
        elif availablePowerPercent < 70:
            setImage('Battery_60')
        elif availablePowerPercent < 90:
            setImage('Battery_80')
        elif availablePowerPercent <= 100:
            setImage('Battery_100')

        sendReport()
        delay(LOOP_DELAY)
        receivePower(LOOP_DELAY*3)
        sendPower()
        delay(LOOP_DELAY*2)

def receivePower(timeDeltaMsec):
    global availablePower
    global receivedPower
    receivedPowerRaw = analogRead(0)
    if receivedPowerRaw > 0:
        receivedPower = math.pow(LOG_BASE, receivedPowerRaw * MULTIPLIER)
        receivedPower = min(receivedPower, CHARGE_RATE * timeDeltaMsec * 0.001)
    else:
        receivedPower = 0
    availablePower += receivedPower
    if availablePower > MAX_STORED_POWER :
        availablePower = MAX_STORED_POWER



def sendPower():
    global availablePower
    totalPowerUsed = 0
    currentWattage = 0
    numberOfSlots = int(getSlotsCount())
    deviceAtPort = False
    for i in range (1, numberOfSlots):
        #Start at 1 because 0 is the input port
        if getAttributeOfDeviceAtSlot('wattage', i):
            currentWattage = float(getAttributeOfDeviceAtSlot('wattage', i))
            deviceAtPort = True
        else:
            currentWattage = 0


        totalPowerUsed += currentWattage
        if deviceAtPort == True:
            if availablePower > currentWattage:
                outputElectricity(i, currentWattage)
                availablePower -= currentWattage
            else:
                outputElectricity(i, 1)

        deviceAtPort = False
    if availablePower < 0:
        availablePower = 0




def sendReport():
    global availablePowerPercent
    IoEClient.reportStates(availablePowerPercent)
    setDeviceProperty(getName(), AVAIL_POWER_PROP, availablePowerPercent)


def setImage(component):
    setComponentOpacity(component, 1)

    if not 'Battery_0' == component :
        setComponentOpacity('Battery_0', 0)
    if not 'Battery_20' == component :
        setComponentOpacity('Battery_20', 0)
    if not 'Battery_40' ==  component :
        setComponentOpacity('Battery_40', 0)
    if not 'Battery_60' ==  component :
        setComponentOpacity('Battery_60', 0)
    if not 'Battery_80' ==  component :
        setComponentOpacity('Battery_80', 0)
    if not 'Battery_100' ==  component :
        setComponentOpacity('Battery_100', 0)


def outputElectricity(port, value):
    global LOG_BASE
    el_log = math.floor(float(math.log(value))/math.log(LOG_BASE))
    if el_log < 0:
        el_log = 0
    elif el_log > 255:
        el_log = 255
    analogWrite(port, el_log)

if __name__ == "__main__":
    main()

